insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'apningskamp', '06', 'Åpning',
  'Åpningskampen — VM er i gang', 'Storyline, arena og gruppe A før Mexico–Sør-Afrika.', 'vm-gruppespill-1', 'lett',
  '[{"category": "Arena", "q": "Hvilket stadion er vert for åpningskampen i VM 2026?", "options": ["MetLife Stadium i New Jersey", "SoFi Stadium i Los Angeles", "Estadio BBVA i Monterrey", "Estadio Azteca i Mexico by"], "correct": 3, "explanation": "Åpningskampen Mexico–Sør-Afrika spilles på Estadio Azteca 11. juni — under VM offisielt «Estadio Ciudad de México» etter FIFAs sponsorregler."}, {"category": "Historie", "q": "Hvilken historisk rekord setter Estadio Azteca med åpningskampen i 2026?", "options": ["Eneste stadion brukt i fem ulike VM", "Første stadion med tak i et VM", "Første stadion som er vert for tre VM-åpningskamper", "Største stadion i VM-historien"], "correct": 2, "explanation": "Azteca var åpningsarena også i 1970 og 1986 — 2026 blir den tredje."}, {"category": "Historie", "q": "Estadio Azteca er det første stadionet som har vært vert for to VM-finaler. Hvilke år?", "options": ["1962 og 1978", "1970 og 1986", "1986 og 2002", "1970 og 1994"], "correct": 1, "explanation": "Mexico arrangerte VM i både 1970 og 1986, begge med finale på Azteca."}, {"category": "Historie", "q": "Hvem vant VM-finalen på Estadio Azteca i 1970?", "options": ["Vest-Tyskland", "Brasil", "Italia", "Uruguay"], "correct": 1, "explanation": "Brasil slo Italia 4–1 og sikret sin tredje VM-tittel, med Pelé på laget."}, {"category": "Stjerner", "q": "Hvilken spiller står bak både «Guds hånd» og «århundrets mål» på Estadio Azteca i 1986?", "options": ["Gary Lineker", "Michel Platini", "Diego Maradona", "Pelé"], "correct": 2, "explanation": "Begge mål kom mot England i kvartfinalen; Argentina vant VM-et det året."}, {"category": "Gruppe A", "q": "Hvilket lag møter vertsnasjonen Mexico i åpningskampen?", "options": ["USA", "Tsjekkia", "Sør-Afrika", "Sør-Korea"], "correct": 2, "explanation": "Mexico–Sør-Afrika åpner mesterskapet 11. juni."}, {"category": "Gruppe A", "q": "Hvilke tre lag er i gruppe A sammen med Mexico?", "options": ["Sør-Afrika, Japan og Polen", "Sør-Korea, Tsjekkia og Uruguay", "Sør-Afrika, Sør-Korea og Tsjekkia", "Sør-Afrika, Sør-Korea og Kroatia"], "correct": 2, "explanation": "Gruppe A spilles fra 11. til 24. juni."}, {"category": "Kuriosa", "q": "VM 2026 er det første mesterskapet med tre vertsnasjoner. Hvilke?", "options": ["USA, Canada og Brasil", "USA, Mexico og Canada", "Canada, Mexico og Costa Rica", "USA, Mexico og Guatemala"], "correct": 1, "explanation": "Kampene fordeles på de tre landene fra 11. juni til 19. juli."}, {"category": "Rekord", "q": "Hvor mange lag deltar i VM 2026 — tidenes største sluttspill?", "options": ["64", "32", "40", "48"], "correct": 3, "explanation": "Utvidet fra 32 lag; totalt 104 kamper, mot 64 tidligere."}, {"category": "Format", "q": "Hvordan er gruppespillet i VM 2026 satt opp?", "options": ["8 grupper med 6 lag", "4 grupper med 12 lag", "12 grupper med 4 lag", "16 grupper med 3 lag"], "correct": 2, "explanation": "De to beste i hver gruppe, pluss de åtte beste treerne, går videre til en ny 32-delsfinale."}]'::jsonb, 'locked', 6, true
)
on conflict (event_id, slug) do update set
  num=excluded.num, phase=excluded.phase, title=excluded.title, sub=excluded.sub,
  hero_img=excluded.hero_img, difficulty=excluded.difficulty, questions=excluded.questions,
  status=excluded.status, sort=excluded.sort, published=excluded.published;

